+function estimateWaitTime(inputData: InputData): number {
+  // Check reservation expiry
+  if (inputData.reservationInfo?.expiresAt) {
+    const msUntilExpiry =
+      inputData.reservationInfo.expiresAt.getTime() - Date.now();
+    if (msUntilExpiry > 0) {
+      return msUntilExpiry;
+    }
