+  const priorityValues: Record<string, number> = {
+    P0: 4,
+    P1: 3,
+    P2: 2,
+    P3: 1,
+    P4: 0,
+  };
+
+  const reqValue = requesting ? (priorityValues[requesting.priority] ?? 2) : 2;
+  const holdValue = holding ? (priorityValues[holding.priority] ?? 2) : 2;
+
+  return reqValue - holdValue;
