+  return [
+    {
+      resources: resources.slice(0, mid),
+      assignedAgentId: holdingAgentId,
+      scope: "First half of resources",
+    },
+    {
+      resources: resources.slice(mid),
+      assignedAgentId: requestingAgentId,
+      scope: "Second half of resources",
+    },
