+  if (!priority) return false;
+  if (priority.deadline) {
+    const msUntil = priority.deadline.getTime() - Date.now();
+    return msUntil < 86400000; // Less than 24 hours
+  }
+  return priority.priority === "P0" || priority.priority === "P1";
