+        probability: 15,
+        mitigation: "Set coordination timeout",
+      });
+      break;
+
+    case "escalate":
+      risks.push({
+        category: "performance",
+        severity: "medium",
+        description: "Both agents may be blocked waiting for human response",
+        probability: 70,
+        mitigation: "Set escalation timeout",
