+  if (breakdown.historicalMatch >= 20) {
+    evidence.push("Strong historical pattern match");
+  }
+
+  if (breakdown.resourceCriticality >= 15) {
+    evidence.push("Resources are low-risk");
+  } else if (breakdown.resourceCriticality < 10) {
