+      return `${strategy} (${confidence}%): Divide resources for parallel work`;
+
+    case "transfer":
+      return `${strategy} (${confidence}%): Priority difference supports transfer`;
+
+    case "coordinate":
+      return `${strategy} (${confidence}%): Both agents can collaborate`;
+
+    case "escalate":
